export type OrbitFinancePluginRequirements = ClientWithRpc<
  GetAccountInfoApi & GetMultipleAccountsApi
> &
  ClientWithPayer &
  ClientWithTransactionPlanning &
  ClientWithTransactionSending;

export function orbitFinanceProgram() {
  return <T extends OrbitFinancePluginRequirements>(client: T) => {
    return {
      ...client,
      orbitFinance: <OrbitFinancePlugin>{
        accounts: {
          binArray: addSelfFetchFunctions(client, getBinArrayCodec()),
          holderGlobalState: addSelfFetchFunctions(
            client,
            getHolderGlobalStateCodec(),
          ),
          liquidityLock: addSelfFetchFunctions(client, getLiquidityLockCodec()),
          nftGlobalState: addSelfFetchFunctions(
            client,
            getNftGlobalStateCodec(),
          ),
          oracle: addSelfFetchFunctions(client, getOracleCodec()),
          pairRegistry: addSelfFetchFunctions(client, getPairRegistryCodec()),
          pool: addSelfFetchFunctions(client, getPoolCodec()),
          position: addSelfFetchFunctions(client, getPositionCodec()),
          positionBin: addSelfFetchFunctions(client, getPositionBinCodec()),
          userHolderState: addSelfFetchFunctions(
            client,
            getUserHolderStateCodec(),
          ),
          userNftState: addSelfFetchFunctions(client, getUserNftStateCodec()),
        },
        instructions: {
          addLiquidityBatch: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAddLiquidityBatchInstructionAsync(input),
            ),
          addLiquidityV2: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAddLiquidityV2Instruction(input),
            ),
          adminFundRewards: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAdminFundRewardsInstruction(input),
            ),
          claimHolderRewards: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClaimHolderRewardsInstructionAsync(input),
            ),
          claimNftRewards: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClaimNftRewardsInstructionAsync(input),
            ),
          claimProtocolFees: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClaimProtocolFeesInstruction(input),
            ),
          closePosition: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClosePositionInstructionAsync(input),
            ),
          createBinArray: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCreateBinArrayInstructionAsync(input),
            ),
          initHolderGlobalState: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitHolderGlobalStateInstructionAsync(input),
            ),
          initNftGlobalState: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitNftGlobalStateInstructionAsync(input),
            ),
          initOracle: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitOracleInstructionAsync(input),
            ),
          initPool: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitPoolInstructionAsync(input),
            ),
          initPosition: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitPositionInstructionAsync(input),
            ),
          initPositionBin: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitPositionBinInstruction(input),
            ),
          initUserHolderState: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitUserHolderStateInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          initUserNftState: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitUserNftStateInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          lockLiquidity: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getLockLiquidityInstructionAsync(input),
            ),
          reconcilePoolDrift: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getReconcilePoolDriftInstruction(input),
            ),
          setPause: (input) =>
            addSelfPlanAndSendFunctions(client, getSetPauseInstruction(input)),
          setPauseBits: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetPauseBitsInstruction(input),
            ),
          swap: (input) =>
            addSelfPlanAndSendFunctions(client, getSwapInstruction(input)),
          syncHolderStake: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSyncHolderStakeInstructionAsync(input),
            ),
          syncRewardIndexes: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSyncRewardIndexesInstructionAsync(input),
            ),
          transferProtocolFees: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getTransferProtocolFeesInstruction(input),
            ),
          unlockLiquidity: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUnlockLiquidityInstructionAsync(input),
            ),
          unpauseOverride: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUnpauseOverrideInstruction(input),
            ),
          updateAdmin: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateAdminInstruction(input),
            ),
          updateAuthorities: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateAuthoritiesInstruction(input),
            ),
          updateFeeConfig: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateFeeConfigInstruction(input),
            ),
          verifyPoolAccounting: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getVerifyPoolAccountingInstruction(input),
            ),
          viewFarmingPosition: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getViewFarmingPositionInstruction(input),
            ),
          withdraw: (input) =>
            addSelfPlanAndSendFunctions(client, getWithdrawInstruction(input)),
        },
      },
    };
  };
}

type MakeOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
